const clientes = $input.all().map(i => i.json);
const comMeta = clientes.filter(c => c.meta_ads_account && c.meta_ads_account.trim() !== '');
if (comMeta.length === 0) {
  throw new Error('Nenhum cliente com conta Meta configurada');
}
return comMeta.map(c => ({ json: { ...c, nome: c.name, grupo_id: c.whatsapp_group_id } }));

const criativos = $('Busca Top Criativos').item.json.data || [];
const insights  = $('Busca Métricas Meta').item.json.data?.[0] || {};
const cliente   = $('Salva Cliente Atual3').item.json;
const vendas    = $('Busca Vendas Supabase').item.json.vendas || [];

// Métricas Meta
const spend = parseFloat(insights.spend || 0);
const impressions = parseInt(insights.impressions || 0);
const actions = insights.actions || [];
const msgIniciadas = actions.find(a =>
  a.action_type === 'onsite_conversion.messaging_conversation_started_7d' ||
  a.action_type === 'messaging_conversation_started_7d' ||
  a.action_type === 'onsite_conversion.total_messaging_connection'
);
const totalMsg = msgIniciadas ? parseInt(msgIniciadas.value) : 0;
const custoMsg = totalMsg > 0 ? spend / totalMsg : 0;

// Métricas Vendas
const totalVendas = vendas.length;
const receita = vendas.reduce((a, v) => a + parseFloat(v.amount || 0), 0);
const ticketMedio = totalVendas > 0 ? receita / totalVendas : 0;
const roas = spend > 0 ? receita / spend : 0;

// Top criativos
const criativosComResultado = criativos
  .map(ad => {
    const adActions = ad.actions || [];
    const adMsg = adActions.find(a =>
      a.action_type === 'onsite_conversion.messaging_conversation_started_7d' ||
      a.action_type === 'messaging_conversation_started_7d'
    );
    const adMsgTotal = adMsg ? parseInt(adMsg.value) : 0;
    const adSpend = parseFloat(ad.spend || 0);
    const adCustoMsg = adMsgTotal > 0 ? adSpend / adMsgTotal : 0;
    return { ad_id: ad.ad_id, nome: ad.ad_name || 'N/A', mensagens: adMsgTotal, custo: adCustoMsg };
  })
  .filter(ad => ad.mensagens > 0)
  .sort((a, b) => b.mensagens - a.mensagens)
  .slice(0, 3);

const hoje = new Date();
const seteDiasAtras = new Date(hoje);
seteDiasAtras.setDate(hoje.getDate() - 7);
const dataFim    = hoje.toLocaleDateString('pt-BR', {day:'2-digit', month:'2-digit', year:'2-digit'});
const dataInicio = seteDiasAtras.toLocaleDateString('pt-BR', {day:'2-digit', month:'2-digit', year:'2-digit'});
const adIds = criativosComResultado.map(c => c.ad_id).filter(Boolean);

return [{ json: {
  criativosComResultado, adIds,
  spend, impressions, totalMsg, custoMsg,
  totalVendas, receita, ticketMedio, roas,
  dataInicio, dataFim,
  grupo_id: cliente.grupo_id,
  nome: cliente.nome
}}];

const raw = $input.first().json;
// Se veio erro da API (adIds vazio ou token inválido), usa objeto vazio
const linksData = (raw && !raw.error && typeof raw === 'object') ? raw : {};
const dados = $('Prepara Dados1').item.json;

const linksMap = {};
Object.keys(linksData).forEach(adId => {
  const ad = linksData[adId];
  if (!ad || typeof ad !== 'object') return;
  const creative = ad.creative || {};
  let link = null;

  if (creative.permalink_url) {
    link = creative.permalink_url;
  } else if (creative.effective_object_story_id) {
    const parts = creative.effective_object_story_id.split('_');
    if (parts.length >= 2) link = 'https://www.facebook.com/' + parts[0] + '/posts/' + parts[1];
  }
  if (!link) link = 'https://www.facebook.com/adsmanager/manage/ads?selected_ad_ids=' + adId;
  linksMap[adId] = link;
});

const criativosComResultado = dados.criativosComResultado || [];
let criativos_texto = '';
if (criativosComResultado.length === 0) {
  criativos_texto = '\nNenhum criativo gerou resultado no periodo.';
} else {
  const label = 'Top ' + criativosComResultado.length + ' Criativo' + (criativosComResultado.length > 1 ? 's' : '');
  criativos_texto = '\n*### ' + label + ' ###*\n';
  criativosComResultado.forEach((ad, i) => {
    const link = linksMap[ad.ad_id] || 'https://www.facebook.com/adsmanager/manage/ads?selected_ad_ids=' + ad.ad_id;
    criativos_texto += '\n' + (i+1) + '. *' + ad.nome + '*\n   ' + link + '\n   Mensagens: ' + ad.mensagens + ' | Custo/msg: R$ ' + ad.custo.toFixed(2) + '\n';
  });
}

const temVendas = dados.totalVendas > 0;
const vendasTexto = temVendas
  ? '\n*Vendas da Semana*\nReceita: R$ ' + dados.receita.toFixed(2) + '\nVendas: ' + dados.totalVendas + '\nTicket Médio: R$ ' + dados.ticketMedio.toFixed(2) + '\nROAS: ' + dados.roas.toFixed(2) + 'x'
  : '\n*Vendas da Semana*\nNenhuma venda registrada no portal esta semana.';

const relatorio = 'Olá! Tudo bem?\nSegue o resumo de performance da *' + dados.nome + '* dos últimos 7 dias\n\n*Período:* ' + dados.dataInicio + ' a ' + dados.dataFim + '\n\n*Meta Ads*\nGasto: R$ ' + dados.spend.toFixed(2) + '\nMensagens iniciadas: ' + dados.totalMsg + '\nCusto por mensagem: R$ ' + dados.custoMsg.toFixed(2) + '\nImpressões: ' + dados.impressions.toLocaleString('pt-BR') + '\n' + criativos_texto + '\n' + vendasTexto + '\n\nQualquer dúvida, estou à disposição!';

return [{ json: { relatorio, grupo_id: dados.grupo_id, nome: dados.nome } }];

